<script setup>
import ArticleHeader from '@/components/ArticleHeader.vue'
import ArticleBody from '@/components/ArticleBody.vue'

const post = {
  id: "springboot-webflux",
  title: "Spring WebFlux와 리액티브 프로그래밍",
  date: "2026-02-11",
  summary: "Spring WebFlux, Project Reactor, Mono/Flux 기초부터 리액티브 REST API 구현까지. 블로킹 vs 논블로킹, 언제 WebFlux를 쓰는지 정리합니다.",
  category: "Technology/SpringBoot",
  tags: ["springboot","webflux","reactive","reactor","backend"],
  content: ["## Spring WebFlux란?", "Spring WebFlux는 논블로킹(non-blocking) 기반의 리액티브 웹 프레임워크입니다. Project Reactor의 Mono/Flux를 사용해 적은 스레드로 많은 동시 요청을 처리할 수 있습니다.", "", "## MVC vs WebFlux", "| 구분 | Spring MVC | Spring WebFlux |", "|------|------------|----------------|", "| 모델 | 블로킹, 스레드당 1요청 | 논블로킹, 이벤트 루프 |", "| 스레드 | 요청당 1스레드 | 공유 스레드 풀 |", "| 적합 | DB·외부 API 블로킹 많을 때 | I/O 대기 많고 동시성 높을 때 |", "", "## 1) 인텔리제이 프로젝트 만들기", "", "**File → New → Project** (Spring Initializr)에서 다음과 같이 설정합니다.", "", "| 항목 | 값 |", "|------|-----|", "| Name | springboot_webflux_example |", "| Language | Java |", "| Build system | Gradle - Groovy |", "| JDK | 21 |", "| Packaging | Jar |", "", "**Dependencies** 선택:", "- **Lombok**", "- **Spring Reactive Web** (`spring-boot-starter-webflux`)", "", "※ `spring-boot-starter-web`과 `spring-boot-starter-webflux`를 동시에 넣으면 MVC가 우선됩니다. WebFlux만 사용하려면 `spring-boot-starter-web`은 제외하세요.", "", "## 2) build.gradle", "", "```groovy", "plugins {", "    id 'java'", "    id 'org.springframework.boot' version '3.4.3'", "    id 'io.spring.dependency-management' version '1.1.7'", "}", "", "group = 'com.example'", "version = '0.0.1-SNAPSHOT'", "", "java {", "    toolchain {", "        languageVersion = JavaLanguageVersion.of(21)", "    }", "}", "", "configurations {", "    compileOnly {", "        extendsFrom annotationProcessor", "    }", "}", "", "repositories {", "    mavenCentral()", "}", "", "dependencies {", "    implementation 'org.springframework.boot:spring-boot-starter-webflux'", "    compileOnly 'org.projectlombok:lombok'", "    annotationProcessor 'org.projectlombok:lombok'", "    testImplementation 'org.springframework.boot:spring-boot-starter-test'", "    testImplementation 'io.projectreactor:reactor-test'", "    testRuntimeOnly 'org.junit.platform:junit-platform-launcher'", "}", "", "tasks.named('test') {", "    useJUnitPlatform()", "}", "```", "", "## 3) 전체 코드 작성", "", "### DemoApplication.java", "```java", "package com.example.springboot_webflux_example;", "", "import org.springframework.boot.SpringApplication;", "import org.springframework.boot.autoconfigure.SpringBootApplication;", "", "@SpringBootApplication", "public class DemoApplication {", "    public static void main(String[] args) {", "        SpringApplication.run(DemoApplication.class, args);", "    }", "}", "```", "", "### Product.java", "```java", "package com.example.springboot_webflux_example;", "", "import lombok.AllArgsConstructor;", "import lombok.Data;", "import lombok.NoArgsConstructor;", "", "@Data", "@AllArgsConstructor", "@NoArgsConstructor", "public class Product {", "    private Long id;", "    private String name;", "    private int price;", "}", "```", "", "### ProductService.java", "```java", "package com.example.springboot_webflux_example;", "", "import org.springframework.stereotype.Service;", "import reactor.core.publisher.Flux;", "import reactor.core.publisher.Mono;", "", "import java.util.Map;", "import java.util.concurrent.ConcurrentHashMap;", "import java.util.concurrent.atomic.AtomicLong;", "", "@Service", "public class ProductService {", "    private final Map<Long, Product> store = new ConcurrentHashMap<>();", "    private final AtomicLong seq = new AtomicLong(1);", "", "    public Flux<Product> findAll() {", "        return Flux.fromIterable(store.values());", "    }", "", "    public Mono<Product> findById(Long id) {", "        return Mono.justOrEmpty(store.get(id));", "    }", "", "    public Mono<Product> save(Product product) {", "        Long id = seq.getAndIncrement();", "        product.setId(id);", "        store.put(id, product);", "        return Mono.just(product);", "    }", "}", "```", "", "### ProductController.java", "```java", "package com.example.springboot_webflux_example;", "", "import org.springframework.http.MediaType;", "import org.springframework.web.bind.annotation.*;", "import reactor.core.publisher.Flux;", "import reactor.core.publisher.Mono;", "", "import java.time.Duration;", "", "@RestController", "@RequestMapping(\"/api/products\")", "public class ProductController {", "    private final ProductService productService;", "", "    public ProductController(ProductService productService) {", "        this.productService = productService;", "    }", "", "    @GetMapping", "    public Flux<Product> list() {", "        return productService.findAll();", "    }", "", "    @GetMapping(\"/{id}\")", "    public Mono<Product> get(@PathVariable Long id) {", "        return productService.findById(id);", "    }", "", "    @PostMapping", "    public Mono<Product> create(@RequestBody Product product) {", "        return productService.save(product);", "    }", "", "    @GetMapping(value = \"/stream\", produces = MediaType.TEXT_EVENT_STREAM_VALUE)", "    public Flux<Product> stream() {", "        return productService.findAll().delayElements(Duration.ofSeconds(1));", "    }", "}", "```", "", "### application.yml", "```yaml", "server:", "  port: 8080", "```", "", "## 4) Postman 테스트", "", "서버를 실행한 뒤 Postman으로 확인합니다.", "", "**① 상품 등록 — POST /api/products**", "```json", "{", "    \"name\": \"키보드\",", "    \"price\": 89000", "}", "```", "→ `{\"id\":1, \"name\":\"키보드\", \"price\":89000}`", "", "**② 전체 조회 — GET /api/products**", "```json", "[{\"id\":1, \"name\":\"키보드\", \"price\":89000}]", "```", "Flux가 JSON 배열로 반환됩니다.", "", "**③ 단건 조회 — GET /api/products/1**", "```json", "{\"id\":1, \"name\":\"키보드\", \"price\":89000}", "```", "Mono가 단일 JSON으로 반환됩니다.", "", "**④ SSE 스트림 — GET /api/products/stream**", "", "Header에 `Accept: text/event-stream`을 설정합니다. 데이터가 1초 간격으로 스트리밍됩니다.", "```", "data:{\"id\":1,\"name\":\"키보드\",\"price\":89000}", "", "data:{\"id\":2,\"name\":\"마우스\",\"price\":45000}", "```", "", "## 5) Mono vs Flux", "- **Mono<T>**: 0 또는 1개의 결과 (비유: Optional)", "- **Flux<T>**: 0~N개의 스트림 (비유: Stream)", "", "```java", "Mono<User> user = userRepo.findById(1L);", "", "Flux<Order> orders = orderRepo.findByUserId(userId);", "", "Mono<User> withOrders = userRepo.findById(1L)", "    .flatMap(u -> orderRepo.findByUserId(u.getId()).collectList())", "    .map(orders -> new UserWithOrders(u, orders));", "```", "", "## 6) 함수형 라우팅 (Router + Handler)", "```java", "@Configuration", "public class RouterConfig {", "    @Bean", "    public RouterFunction<ServerResponse> route(ProductHandler handler) {", "        return RouterFunctions", "            .route(GET(\"/api/v2/products\"), handler::list)", "            .andRoute(GET(\"/api/v2/products/{id}\"), handler::get);", "    }", "}", "", "@Component", "public class ProductHandler {", "    private final ProductRepository repo;", "    public Mono<ServerResponse> list(ServerRequest req) {", "        return ServerResponse.ok()", "            .body(repo.findAll(), Product.class);", "    }", "}", "```", "", "## 7) WebClient (리액티브 HTTP 클라이언트)", "```java", "@Service", "public class ExternalApiService {", "    private final WebClient webClient;", "", "    public ExternalApiService(WebClient.Builder builder) {", "        this.webClient = builder.baseUrl(\"https://api.example.com\").build();", "    }", "", "    public Mono<ApiResponse> fetch(String id) {", "        return webClient.get().uri(\"/items/{id}\", id)", "            .retrieve()", "            .bodyToMono(ApiResponse.class);", "    }", "}", "```", "", "## 언제 WebFlux를 쓸까", "- 고동시성, 저지연이 중요한 서비스(실시간, SSE, WebSocket)", "- 외부 API 호출이 많고 논블로킹 I/O로 이득을 볼 때", "- 기존 스택이 리액티브(예: R2DBC, MongoDB 리액티브 드라이버)일 때", "", "※ DB가 JDBC(블로킹)이면 WebFlux 이점이 줄어듭니다. R2DBC 등 리액티브 DB 드라이버와 함께 써야 진가를 발휘합니다.", "", "## 정리", "Spring WebFlux는 논블로킹·리액티브 스택의 핵심입니다. 실무에서는 트래픽 패턴과 기존 DB/외부 연동 방식에 따라 MVC vs WebFlux를 선택하면 됩니다."]
}
</script>

